// Solution
function maxConsecutiveOnes(arr) {
	let maxCount = 0;
	let currentCount = 0;
	for (let i = 0; i < arr.length; i++) {
		if (arr[i] === 1) {
			currentCount++;
		}
		else {
			currentCount = 0;
		}
		if (currentCount > maxCount) {
			maxCount = currentCount;
		}
	}
	return maxCount;
}
